record.field:
for rec in records:
    if rec.x_tor_state and rec.x_tor_state != 'draft':
        continue

    values = {}
    if rec.partner_name and not rec.x_tor_recipient_name:
        values['x_tor_recipient_name'] = rec.partner_name

    if rec.job_id:
        if rec.job_id.name and rec.x_tor_job_title != rec.job_id.name:
            values['x_tor_job_title'] = rec.job_id.name
        if rec.job_id.department_id and rec.x_tor_department_id != rec.job_id.department_id:
            values['x_tor_department_id'] = rec.job_id.department_id.id

    if values:
        rec.sudo().write(values)

for rec in records:
    if not rec.x_tor_signed_attachment_id:
        continue

    rec.sudo().write({
        'x_tor_state': 'signed',
        'x_tor_signed_on': datetime.datetime.now(),
    })
    rec.message_post(body='Signed TOR PDF linked to the applicant record.')
